It seems verilator is crashing on this line of code :

```
module exe
(
....
 input  logic [XLEN-1:0]            mepc_q_i,
 input  logic [XLEN-1:0]            mtvec_q_i,
 input  logic [XLEN-1:0]            mstatus_q_i,
 input  logic [11:0]                mie_q_i,
 input  logic [11:0]                mip_q_i
....
);

....
logic [XLEN-1:0]          cause_nxt;
logic [XLEN-2:0]          mcause_nxt;
logic [XLEN-1:0]          mepc_nxt;
logic [XLEN-1:0]          mtval_nxt;
logic [XLEN-1:0]          mstatus_old;
logic [12:11]             mpp_old_q;
logic                     mpie_old_q;
logic                     mie_old_q;
logic [12:11]             mpp_new;
logic                     mpie_new;
logic                     mie_new;
logic [XLEN-1:0]          mstatus_nxt;
logic [XLEN-1:0]          cause_q;
logic [XLEN-1:0]          mstatus_q;
logic [XLEN-1:0]          mtval_q;
logic [XLEN-1:0]          mepc_q;
logic                     pc_missaligned_e0;
logic                     adr_missaligned;
logic                     ld_adr_missaligned;
logic                     st_adr_missaligned;
logic [1:0]               core_mode_nxt;
logic [1:0]               core_mode_q;
....

assign mpp_old_q[12:11] = mstatus_q_i[12:11];
assign mpie_old_q       = mstatus_q_i[7];
assign mie_old_q        = mstatus_q_i[3];

...



assign mpp_new[12:11] = {2{exception_v | interrupt_v}} & mpp_old_q
                      | {2{mret_v_e0                   }} & core_mode_q;  // return to user after mret
assign mpie_new       = (exception_v | interrupt_v) & mie_old_q
                      | mret_v_e0;

assign mie_new        = ~mret_v_e0 & ~(interrupt_v | exception_v) // disable interrupt when trap taken
                      |  mret_v_e0 & mpie_old_q;

assign mstatus_nxt = {
                        mstatus_old[31:13],
                        mpp_new[12:11],
                        mstatus_old[10:8],
                        mpie_new,
                        mstatus_old[6:4],
                        mie_new,
                        mstatus_old[2:0]
                      };
....
endmodule
```

The above lines are an extract of the file causing the crash, it seems if i remove the line creating the error it's working, maybe it's link to the declaration ``logic [12:10] sig;`` but this is valid verilog so i doubt it.


What 'verilator' command line do we use to run your example?

```
verilator ../riscv_pkg.sv -CFLAGS "-lsystemc -lm -g -DVALIDATION -O0 -I../include/ELFIO/" -sc -Wno-fatal -Wall --trace --pins-sc-uint -DVALIDATION ../src/csr.sv ../src/shifter.sv ../src/ifetch1.sv ../src/bu.sv ../src/koggeStone33.sv ../src/rf.sv ../src/core.sv ../src/lsu.sv ../src/dec1.sv ../src/decoder.sv ../src/dec0.sv ../src/exe.sv ../src/btb.sv ../src/alu.sv ../src/ifetch0.sv --top-module core --exe core_tb.cpp --Mdir obj_dir
```

